const express = require('express');
const app = express();

// ── Middleware ────────────────────────────────────────────────────────────────

// Parse JSON bodies with a size limit to prevent payload bombing
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Basic security headers (use `helmet` package for a more complete solution)
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Referrer-Policy', 'no-referrer');
  next();
});

// ── Routes ────────────────────────────────────────────────────────────────────

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate and sanitize query parameters
    const { page = '1', limit = '10' } = req.query;

    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);

    if (isNaN(pageNum) || pageNum < 1) {
      return res.status(400).json({ error: '`page` must be a positive integer.' });
    }
    if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
      return res.status(400).json({ error: '`limit` must be an integer between 1 and 100.' });
    }

    // Replace with real DB query in production
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json({ data: users, page: pageNum, limit: limitNum });
  } catch (err) {
    next(err); // Forward unexpected errors to the error handler
  }
});

// ── 404 Handler ───────────────────────────────────────────────────────────────

app.use((req, res) => {
  res.status(404).json({ error: 'Route not found.' });
});

// ── Central Error Handler ─────────────────────────────────────────────────────

// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Avoid leaking internal details in production
  const isDev = process.env.NODE_ENV !== 'production';
  console.error(err);
  res.status(err.status || 500).json({
    error: isDev ? err.message : 'An internal server error occurred.',
  });
});

// ── Start Server ──────────────────────────────────────────────────────────────

const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

